3516 // This function tries to fold the following operations:
3517 //   (x < y) ? -1 : zext(x != y)
3518 //   (x < y) ? -1 : zext(x > y)
3519 //   (x > y) ? 1 : sext(x != y)
3520 //   (x > y) ? 1 : sext(x < y)
3521 // Into ucmp/scmp(x, y), where signedness is determined by the signedness
3522 // of the comparison in the original sequence.
3523 Instruction *InstCombinerImpl::foldSelectToCmp(SelectInst &SI) {
3524   Value *TV = SI.getTrueValue();
3525   Value *FV = SI.getFalseValue();
3526 
3527   ICmpInst::Predicate Pred;
3528   Value *LHS, *RHS;
3529   if (!match(SI.getCondition(), m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
3530     return nullptr;
3531 
3532   if (!LHS->getType()->isIntOrIntVectorTy())
3533     return nullptr;
3534 
3535   // Try to swap operands and the predicate. We need to be careful when doing
3536   // so because two of the patterns have opposite predicates, so use the
3537   // constant inside select to determine if swapping operands would be
3538   // beneficial to us.
3539   if ((ICmpInst::isGT(Pred) && match(TV, m_AllOnes())) ||
3540       (ICmpInst::isLT(Pred) && match(TV, m_One()))) {
3541     Pred = ICmpInst::getSwappedPredicate(Pred);
3542     std::swap(LHS, RHS);
3543   }
3544   bool IsSigned = ICmpInst::isSigned(Pred);
3545 
3546   bool Replace = false;
3547   ICmpInst::Predicate ExtendedCmpPredicate;
3548   // (x < y) ? -1 : zext(x != y)
3549   // (x < y) ? -1 : zext(x > y)
3550   if (ICmpInst::isLT(Pred) && match(TV, m_AllOnes()) &&
3551       match(FV, m_ZExt(m_c_ICmp(ExtendedCmpPredicate, m_Specific(LHS),
3552                                 m_Specific(RHS)))) &&
3553       (ExtendedCmpPredicate == ICmpInst::ICMP_NE ||
3554        ICmpInst::getSwappedPredicate(ExtendedCmpPredicate) == Pred))
3555     Replace = true;
3556 
3557   // (x > y) ? 1 : sext(x != y)
3558   // (x > y) ? 1 : sext(x < y)
3559   if (ICmpInst::isGT(Pred) && match(TV, m_One()) &&
3560       match(FV, m_SExt(m_c_ICmp(ExtendedCmpPredicate, m_Specific(LHS),
3561                                 m_Specific(RHS)))) &&
3562       (ExtendedCmpPredicate == ICmpInst::ICMP_NE ||
3563        ICmpInst::getSwappedPredicate(ExtendedCmpPredicate) == Pred))
3564     Replace = true;
3565 
3566   // (x == y) ? 0 : (x > y ? 1 : -1)
3567   ICmpInst::Predicate FalseBranchSelectPredicate;
3568   const APInt *InnerTV, *InnerFV;
3569   if (Pred == ICmpInst::ICMP_EQ && match(TV, m_Zero()) &&
3570       match(FV, m_Select(m_c_ICmp(FalseBranchSelectPredicate, m_Specific(LHS),
3571                                   m_Specific(RHS)),
3572                          m_APInt(InnerTV), m_APInt(InnerFV)))) {
3573     if (!ICmpInst::isGT(FalseBranchSelectPredicate)) {
3574       FalseBranchSelectPredicate =
3575           ICmpInst::getSwappedPredicate(FalseBranchSelectPredicate);
3576       std::swap(LHS, RHS);
3577     }
3578 
3579     if (!InnerTV->isOne()) {
3580       std::swap(InnerTV, InnerFV);
3581       std::swap(LHS, RHS);
3582     }
3583 
3584     if (ICmpInst::isGT(FalseBranchSelectPredicate) && InnerTV->isOne() &&
3585         InnerFV->isAllOnes()) {
3586       IsSigned = ICmpInst::isSigned(FalseBranchSelectPredicate);
3587       Replace = true;
3588     }
3589   }
3590 
3591   Intrinsic::ID IID = IsSigned ? Intrinsic::scmp : Intrinsic::ucmp;
3592   if (Replace)
3593     return replaceInstUsesWith(
3594         SI, Builder.CreateIntrinsic(SI.getType(), IID, {LHS, RHS}));
3595   return nullptr;
3596 }
