3606 static bool matchFMulByZeroIfResultEqZero(InstCombinerImpl &IC, Value *Cmp0,
3607                                           Value *Cmp1, Value *TrueVal,
3608                                           Value *FalseVal, Instruction &CtxI,
3609                                           bool SelectIsNSZ) {
3610   Value *MulRHS;
3611   if (match(Cmp1, m_PosZeroFP()) &&
3612       match(TrueVal, m_c_FMul(m_Specific(Cmp0), m_Value(MulRHS)))) {
3613     FastMathFlags FMF = cast<FPMathOperator>(TrueVal)->getFastMathFlags();
3614     // nsz must be on the select, it must be ignored on the multiply. We
3615     // need nnan and ninf on the multiply for the other value.
3616     FMF.setNoSignedZeros(SelectIsNSZ);
3617     return IC.fmulByZeroIsZero(MulRHS, FMF, &CtxI);
3618   }
3619 
3620   return false;
3621 }
