3623 /// Check whether the KnownBits of a select arm may be affected by the
3624 /// select condition.
3625 static bool hasAffectedValue(Value *V, SmallPtrSetImpl<Value *> &Affected,
3626                              unsigned Depth) {
3627   if (Depth == MaxAnalysisRecursionDepth)
3628     return false;
3629 
3630   // Ignore the case where the select arm itself is affected. These cases
3631   // are handled more efficiently by other optimizations.
3632   if (Depth != 0 && Affected.contains(V))
3633     return true;
3634 
3635   if (auto *I = dyn_cast<Instruction>(V)) {
3636     if (isa<PHINode>(I)) {
3637       if (Depth == MaxAnalysisRecursionDepth - 1)
3638         return false;
3639       Depth = MaxAnalysisRecursionDepth - 2;
3640     }
3641     return any_of(I->operands(), [&](Value *Op) {
3642       return Op->getType()->isIntOrIntVectorTy() &&
3643              hasAffectedValue(Op, Affected, Depth + 1);
3644     });
3645   }
3646 
3647   return false;
3648 }
