3650 // This transformation enables the possibility of transforming fcmp + sel into
3651 // a fmaxnum/fminnum intrinsic.
3652 static Value *foldSelectIntoAddConstant(SelectInst &SI,
3653                                         InstCombiner::BuilderTy &Builder) {
3654   // Do this transformation only when select instruction gives NaN and NSZ
3655   // guarantee.
3656   auto *SIFOp = dyn_cast<FPMathOperator>(&SI);
3657   if (!SIFOp || !SIFOp->hasNoSignedZeros() || !SIFOp->hasNoNaNs())
3658     return nullptr;
3659 
3660   // select((fcmp Pred, X, 0), (fadd X, C), C)
3661   //      => fadd((select (fcmp Pred, X, 0), X, 0), C)
3662   //
3663   // Pred := OGT, OGE, OLT, OLE, UGT, UGE, ULT, and ULE
3664   Instruction *FAdd;
3665   Constant *C;
3666   Value *X, *Z;
3667   CmpInst::Predicate Pred;
3668 
3669   // Note: OneUse check for `Cmp` is necessary because it makes sure that other
3670   // InstCombine folds don't undo this transformation and cause an infinite
3671   // loop. Furthermore, it could also increase the operation count.
3672   if (match(&SI, m_Select(m_OneUse(m_FCmp(Pred, m_Value(X), m_Value(Z))),
3673                           m_OneUse(m_Instruction(FAdd)), m_Constant(C))) ||
3674       match(&SI, m_Select(m_OneUse(m_FCmp(Pred, m_Value(X), m_Value(Z))),
3675                           m_Constant(C), m_OneUse(m_Instruction(FAdd))))) {
3676     // Only these relational predicates can be transformed into maxnum/minnum
3677     // intrinsic.
3678     if (!CmpInst::isRelational(Pred) || !match(Z, m_AnyZeroFP()))
3679       return nullptr;
3680 
3681     if (!match(FAdd, m_FAdd(m_Specific(X), m_Specific(C))))
3682       return nullptr;
3683 
3684     Value *NewSelect = Builder.CreateSelect(SI.getCondition(), X, Z, "", &SI);
3685     NewSelect->takeName(&SI);
3686 
3687     Value *NewFAdd = Builder.CreateFAdd(NewSelect, C);
3688     NewFAdd->takeName(FAdd);
3689 
3690     // Propagate FastMath flags
3691     FastMathFlags SelectFMF = SI.getFastMathFlags();
3692     FastMathFlags FAddFMF = FAdd->getFastMathFlags();
3693     FastMathFlags NewFMF = FastMathFlags::intersectRewrite(SelectFMF, FAddFMF) |
3694                            FastMathFlags::unionValue(SelectFMF, FAddFMF);
3695     cast<Instruction>(NewFAdd)->setFastMathFlags(NewFMF);
3696     cast<Instruction>(NewSelect)->setFastMathFlags(NewFMF);
3697 
3698     return NewFAdd;
3699   }
3700 
3701   return nullptr;
3702 }
