3375 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,
3376                                         const APInt *Cond1, Value *CtlzOp,
3377                                         unsigned BitWidth,
3378                                         bool &ShouldDropNUW) {
3379   // The challenge in recognizing std::bit_ceil(X) is that the operand is used
3380   // for the CTLZ proper and select condition, each possibly with some
3381   // operation like add and sub.
3382   //
3383   // Our aim is to make sure that -ctlz & (BitWidth - 1) == 0 even when the
3384   // select instruction would select 1, which allows us to get rid of the select
3385   // instruction.
3386   //
3387   // To see if we can do so, we do some symbolic execution with ConstantRange.
3388   // Specifically, we compute the range of values that Cond0 could take when
3389   // Cond == false.  Then we successively transform the range until we obtain
3390   // the range of values that CtlzOp could take.
3391   //
3392   // Conceptually, we follow the def-use chain backward from Cond0 while
3393   // transforming the range for Cond0 until we meet the common ancestor of Cond0
3394   // and CtlzOp.  Then we follow the def-use chain forward until we obtain the
3395   // range for CtlzOp.  That said, we only follow at most one ancestor from
3396   // Cond0.  Likewise, we only follow at most one ancestor from CtrlOp.
3397 
3398   ConstantRange CR = ConstantRange::makeExactICmpRegion(
3399       CmpInst::getInversePredicate(Pred), *Cond1);
3400 
3401   ShouldDropNUW = false;
3402 
3403   // Match the operation that's used to compute CtlzOp from CommonAncestor.  If
3404   // CtlzOp == CommonAncestor, return true as no operation is needed.  If a
3405   // match is found, execute the operation on CR, update CR, and return true.
3406   // Otherwise, return false.
3407   auto MatchForward = [&](Value *CommonAncestor) {
3408     const APInt *C = nullptr;
3409     if (CtlzOp == CommonAncestor)
3410       return true;
3411     if (match(CtlzOp, m_Add(m_Specific(CommonAncestor), m_APInt(C)))) {
3412       CR = CR.add(*C);
3413       return true;
3414     }
3415     if (match(CtlzOp, m_Sub(m_APInt(C), m_Specific(CommonAncestor)))) {
3416       ShouldDropNUW = true;
3417       CR = ConstantRange(*C).sub(CR);
3418       return true;
3419     }
3420     if (match(CtlzOp, m_Not(m_Specific(CommonAncestor)))) {
3421       CR = CR.binaryNot();
3422       return true;
3423     }
3424     return false;
3425   };
3426 
3427   const APInt *C = nullptr;
3428   Value *CommonAncestor;
3429   if (MatchForward(Cond0)) {
3430     // Cond0 is either CtlzOp or CtlzOp's parent.  CR has been updated.
3431   } else if (match(Cond0, m_Add(m_Value(CommonAncestor), m_APInt(C)))) {
3432     CR = CR.sub(*C);
3433     if (!MatchForward(CommonAncestor))
3434       return false;
3435     // Cond0's parent is either CtlzOp or CtlzOp's parent.  CR has been updated.
3436   } else {
3437     return false;
3438   }
3439 
3440   // Return true if all the values in the range are either 0 or negative (if
3441   // treated as signed).  We do so by evaluating:
3442   //
3443   //   CR - 1 u>= (1 << BitWidth) - 1.
3444   APInt IntMax = APInt::getSignMask(BitWidth) - 1;
3445   CR = CR.sub(APInt(BitWidth, 1));
3446   return CR.icmp(ICmpInst::ICMP_UGE, IntMax);
3447 }
